              "type": "string"
            },
            "parameters": {
              "$ref": "#/$defs/operation-step-parameters"
            }
          }
        },
        {
          "oneOf": [
            {
              "required": [
                "operationId"
              ]
            },
            {
              "require

d": [
                "operationPath"
              ]
            }
          ]
        }
      ],
