              "correlationId"
            ]
          },
          "then": {
            "properties": {
              "action": {
                "const": "receive"
              }
            },
            "required": [
              "action"
            ]
          }
        },
        {
          "oneOf": [
            {
              "required": [
                "operationId"
              ]
            },
            {
              "required": [
                "channelPath"
              ]
            }
          ]
