    "criterion-object": {
      "$comment": "https://spec.openapis.org/arazzo/v1.1#criterion-object",
      "description": "An object used to specify the context, conditions, and condition ty

pes\nthat can be used to prove or satisfy assertions specified in Step Object successCriteria,\nSuccess Action Object criteria, and Failure Action Object criteria",
      "type": "object",
      "properties": {
        "context": {
          "description": "A runtime expression used to set the context for the condition to be applied on",
          "type": "string"
        },
        "condition": {
          "description": "The condition to apply",
          "type": "string"
        },
        "type": {
          "description": "The type of condition to be applied or a reference to an expression type object",
          "oneOf": [
            {
              "type": "string",
              "enum": [
                "simple",
                "regex",
                "jsonpath",
                "xpath"
              ],
              "default": "simple"
            },
            {
              "$ref": "#/$defs/expression-type-object"
            }
          ]
        }
      },
      "required": [
        "condition"
