                "required": [
                  "workflowId"
                ]
              },
              {
                "required": [
                  "stepId"
                ]
              }
            ]
          }
        },
        {
          "if": {
            "required": [
              "parameters"
            ]
          },
          "then": {
            "required": [
              "workflowId"
            ]
          }
        }
      ],
      "required": [
